using System.ComponentModel;
using System.Net;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using Microsoft.Agents.AI.ChatCompletion;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable or AI:ApiKey in configuration.");

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient("gpt-4o-mini-2024-07-18", apiKey));
builder.Services.AddSingleton<ResearchTools>();

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var tools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(
    chatClient,
    "ResearchAgent",
    "You are a research assistant. When given a topic, use the WebSearch tool " +
    "to find information, the SaveNote tool to record key findings, and the " +
    "GetNotes tool to review what you've collected. Search multiple times to " +
    "gather diverse perspectives. After gathering enough information, call " +
    "GetNotes to review everything, then provide a comprehensive summary.")
{
    Tools = [
        AIFunctionFactory.Create(tools.WebSearch),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ],
};

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User,
        $"Research the following topic thoroughly. Search for information, save " +
        $"important findings as notes, then provide a comprehensive summary.\n\nTopic: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant && !string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n=== Research Complete ===");
Console.WriteLine($"Notes collected: {tools.NoteCount}");

/// <summary>Tools available to the research agent.</summary>
sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    public int NoteCount => _notes.Count;

    [Description("Search the web for information on a query. Returns search result snippets.")]
    public async Task<string> WebSearch(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  🔍 Searching: {query}");
        try
        {
            // Uses DuckDuckGo Lite which returns HTML results without requiring an API key
            var encoded = WebUtility.UrlEncode(query);
            var request = new HttpRequestMessage(HttpMethod.Get,
                $"https://lite.duckduckgo.com/lite/?q={encoded}");
            request.Headers.UserAgent.ParseAdd(
                "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

            var response = await _http.SendAsync(request);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            var snippets = ExtractSnippets(html);
            return snippets.Length > 0
                ? snippets
                : $"No detailed results found for '{query}'. Try rephrasing.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }

    [Description("Save an important finding as a note for later summarization.")]
    public string SaveNote(
        [Description("A concise note capturing a key finding")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  📝 Note #{_notes.Count} saved");
        return $"Note saved (total: {_notes.Count}).";
    }

    [Description("Retrieve all saved notes to review before writing a summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet. Use SaveNote to record findings.";

        Console.WriteLine($"  📋 Reviewing {_notes.Count} notes");
        return string.Join("\n",
            _notes.Select((n, i) => $"{i + 1}. {n}"));
    }

    private static string ExtractSnippets(string html)
    {
        // Extract text between <td> snippet cells from DuckDuckGo Lite results
        var results = new List<string>();
        var span = html.AsSpan();
        const string snippetMarker = "class=\"result-snippet\"";

        int pos = 0;
        while (results.Count < 6)
        {
            int markerIdx = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal);
            if (markerIdx < 0) break;

            int gtIdx = html.IndexOf('>', markerIdx + snippetMarker.Length);
            if (gtIdx < 0) break;

            int endIdx = html.IndexOf("</td>", gtIdx, StringComparison.Ordinal);
            if (endIdx < 0) break;

            var snippet = html[(gtIdx + 1)..endIdx]
                .Replace("<b>", "").Replace("</b>", "")
                .Replace("&amp;", "&").Replace("&quot;", "\"")
                .Replace("&#x27;", "'").Replace("&lt;", "<")
                .Replace("&gt;", ">").Trim();

            if (snippet.Length > 20)
                results.Add(snippet);

            pos = endIdx + 5;
        }

        return string.Join("\n\n", results);
    }
}

