using System.ComponentModel;
using System.Net;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";
var openAIClient = new OpenAIClient(apiKey);
IChatClient chatClient = openAIClient.GetChatClient(modelId).AsIChatClient();

var tools = new ResearchTools();

var agent = new ChatClientAgent(
    chatClient,
    instructions: "You are a research assistant. When given a topic, use the WebSearch tool " +
        "to find information, the SaveNote tool to record key findings, and the " +
        "GetNotes tool to review what you've collected. Search multiple times to " +
        "gather diverse perspectives. After gathering enough information, call " +
        "GetNotes to review everything, then provide a comprehensive summary.",
    name: "ResearchAgent",
    tools: [
        AIFunctionFactory.Create(tools.WebSearch),
        AIFunctionFactory.Create(tools.SaveNote),
        AIFunctionFactory.Create(tools.GetNotes),
    ]);

Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly. Search for information, save " +
    $"important findings as notes, then provide a comprehensive summary.\n\nTopic: {topic}",
    options: runOptions))
{
    if (update.Role == ChatRole.Assistant && !string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine("\n\n=== Research Complete ===");
Console.WriteLine($"Notes collected: {tools.NoteCount}");

