69. 
70.     [Description("Search the web for information on a query. Returns search result snippets.")]
71.     public async Task<string> WebSearch(
72.         [Description("The search query")] string query)
73.     {
74.         Console.WriteLine($"  🔍 Searching: {query}");
75.         try
76.         {
77.             // Uses DuckDuckGo Lite which returns HTML results without requiring an API key
78.             var encoded = WebUtility.UrlEncode(query);
79.             var request = new HttpRequestMessage(HttpMethod.Get,
80.                 $"https://lite.duckduckgo.com/lite/?q={encoded}");
81.             request.Headers.UserAgent.ParseAdd(
82.                 "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
83. 
84.             var response = await _http.SendAsync(request);
85.             response.EnsureSuccessStatusCode();
86.             var html = await response.Content.ReadAsStringAsync();
87. 
88.             var snippets = ExtractSnippets(html);
89.             return snippets.Length > 0
90.                 ? snippets
91.                 : $"No detailed results found for '{query}'. Try rephrasing.";
92.         }
93.         catch (Exception ex)
94.         {
95.             return $"Search failed: {ex.Message}. Try a different query.";
96.         }
97.     }
98. 
99.     [Description("Save an important finding as a note for later summarization.")]
100.     public string SaveNote(
101.         [Description("A concise note capturing a key finding")] string note)
102.     {
103.         _notes.Add(note);
104.         Console.WriteLine($"  📝 Note #{_notes.Count} saved");
105.         return $"Note saved (total: {_notes.Count}).";
106.     }
107. 
108.     [Description("Retrieve all saved notes to review before writing a summary.")]
109.     public string GetNotes()
110.     {
111.         if (_notes.Count == 0)
112.             return "No notes saved yet. Use SaveNote to record findings.";
113. 
114.         Console.WriteLine($"  📋 Reviewing {_notes.Count} notes");
115.         return string.Join("\n",
116.             _notes.Select((n, i) => $"{i + 1}. {n}"));
117.     }
118. 
119.     private static string ExtractSnippets(string html)
120.     {
121.         // Extract text between <td> snippet cells from DuckDuckGo Lite results
122.         var results = new List<string>();
123.         var span = html.AsSpan();
124.         const string snippetMarker = "class=\"result-snippet\"";
125. 
126.         int pos = 0;
127.         while (results.Count < 6)
128.         {
129.             int markerIdx = html.IndexOf(snippetMarker, pos, StringComparison.Ordinal);
130.             if (markerIdx < 0) break;
131. 
132.             int gtIdx = html.IndexOf('>', markerIdx + snippetMarker.Length);
133.             if (gtIdx < 0) break;
134. 
135.             int endIdx = html.IndexOf("</td>", gtIdx, StringComparison.Ordinal);
136.             if (endIdx < 0) break;
137. 
138.             var snippet = html[(gtIdx + 1)..endIdx]
139.                 .Replace("<b>", "").Replace("</b>", "")
140.                 .Replace("&amp;", "&").Replace("&quot;", "\"")
141.                 .Replace("&#x27;", "'").Replace("&lt;", "<")
142.                 .Replace("&gt;", ">").Trim();
143. 
144.             if (snippet.Length > 20)
145.                 results.Add(snippet);
146. 
147.             pos = endIdx + 5;
148.         }
149. 
150.         return string.Join("\n\n", results);
151.     }
152. }
