             request.Headers.UserAgent.ParseAdd(
                 "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

             var response = await _http.SendAsync(request);
             response.EnsureSuccessStatusCode();
             var html = await response.Content.ReadAsStringAsync();

             var snippets = ExtractSnippets(html);
             return snippets.Length > 0
                 ? snippets
                 : $"No detailed results found for '{query}'. Try rephrasing.";
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Save an important finding as a note for later summarization.")]
     public string SaveNote(
         [Description("A concise note capturing a key finding")] string note)
     {
         _notes.Add(note);
         Console.WriteLine($"  📝 Note #{_notes.Count} saved");
         return $"Note saved (total: {_notes.Count}).";
     }

     [Description("Retrieve all saved notes to review before writing a summary.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet. Use SaveNote to record findings.";

         Console.WriteLine($"  📋 Reviewing {_notes.Count} notes");
         return string.Join("\n",
             _notes.Select((n, i) => $"{i + 1}. {n}"));
     }

     private static string ExtractSnippets(string html)
     {
         // Extract text between <td> snippet cells from DuckDuckGo Lite results
